var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"과자 부스러기, ……찢어진 휴지 조각, ……살 점 붙은 뼈다귀.","JPN":"お菓子の食べかす……破れたティッシュの切れ端……肉がついている骨。","ENG":"Cookie crumbs. Torn napkins. Meaty bones.","TWN":"餅乾渣……撕碎的廢紙……帶肉的骨頭。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"후우.","JPN":"ふぅ。","ENG":"*Sigh...*","TWN":"呼。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"분명히 외출 전에 먼지 한 톨 없이, 깔끔하게 청소하고 나갔을 텐데…….","JPN":"出かける前に綺麗に片づけて、埃一つない状態にしておいたはずなのに……","ENG":"I believe I left the place sparkly clean.","TWN":"我明明出門前才打掃得一塵不染的……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경. 또 집무실을 잔뜩 어지럽혀 놨군.","JPN":"リブ卿、また執務室を散らかしたな。","ENG":"It must be Dame Liv. She messed it up again.","TWN":"看來莉芙卿又把辦公室弄亂了。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이제 한솔 경과 에리어스 경도 있는데 대체 언제 철이 들 작정인 건지.","JPN":"今はヤガミ卿とアリウス卿もいるというのに、いつになったら大人になるんだ……","ENG":"What if Sir Hansol and Dame Arius take after her? Will she ever grow up?","TWN":"現在還有楊瀚卿和埃里奧斯卿在，她到底要什麼時候才會長大呢？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"응? 뭐가 깨져 있는 거지?","JPN":"ん？　何か割れている……？","ENG":"Hm? Something broke.","TWN":"嗯？好像有什麼東西摔破了？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……이, 이건!?","JPN":"……こ、これは！？","ENG":"...Th-this...!","TWN":"……這…這不是？！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 전원 긴급 소집이라니. 무슨 일이야, 부단장?","JPN":"全員緊急招集って、いったいどういうこと？　副団長。","ENG":"What? What's this emergency call-up about? What's going on, Deputy?","TWN":"什麼嘛，幹嘛突然全員緊急集合，有什麼事嗎，副團長？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피오네 언니… 표정이 무서워요.","JPN":"フィオネさん……顔が怖いです。","ENG":"Fione... You look scary.","TWN":"菲奧尼姊姊……表情好恐怖。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"유감스럽게도 아주 중대한 사건이 발생했습니다.","JPN":"残念ながら、一大事が起きました。","ENG":"Something very unfortunate and tragic has happened.","TWN":"我很遺憾，這裡發生了重大事件。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……이걸 보십시오.","JPN":"……これを見てください。","ENG":"...Look.","TWN":"……請看這個。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응? 머그컵?","JPN":"ん？　マグカップ？","ENG":"Hm? It's a mug.","TWN":"嗯？馬克杯？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"깨져있네? 누가 깨뜨렸담?","JPN":"割れてるね。誰がやったんだろ。","ENG":"It's broken. Who broke it?","TWN":"破咧？是誰摔破的？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"근데 그냥 치우면 되잖아. 왜 중대한 사건이라는 거야?","JPN":"って、割れたなら片付ければいいじゃん。それの何が一大事なの？","ENG":"So? You could just get rid of it. What's so unfortunate and tragic about it?","TWN":"不過掃一下就好啦？哪是什麼重大事件？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잘 떠올려 보십시오. 이건 그냥 머그컵이 아닙니다.","JPN":"よく考えてください。これはただのマグカップではありません。","ENG":"Think hard. This isn't just a mug.","TWN":"你看仔細，這可不是普通的馬克杯。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어? 그럼 아티팩트였어? 내 눈에는 평범한 머그컵으로 보이는데?","JPN":"えっ？　もしかしてアーティファクト？　私には普通のカップに見えるんだけど。","ENG":"Then, what? Is that an Artifact? But to me, it just looks like an ordinary mug.","TWN":"喔？是人造神器嗎？我看起來就是個普通的馬克杯啊？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어라, 저 어디선가 이 컵 본 것 같아요.","JPN":"あれっ？　私、あのマグカップどこかで見た気がします。","ENG":"Err, I think I've seen this mug somewhere.","TWN":"喔喔！我好像在哪看過這個馬克杯。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아아! 이 머그컵, 단장님이 아끼는 컵이에요.","JPN":"ああっ！　このマグカップ、団長のお気に入りでした！","ENG":"Ah! It's the Captain's favorite mug.","TWN":"我想起來了！這個馬克杯，是團長很寶貝的杯子。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};